package com.example.userapp.network;

import android.util.Log;

import java.io.IOException;

import okhttp3.Interceptor;
import okhttp3.Request;
import okhttp3.Response;

public class RetryInterceptor implements Interceptor {

    private static final String TAG = "RetryInterceptor";
    private final int maxRetries;

    public RetryInterceptor(int maxRetries) {
        this.maxRetries = maxRetries;
    }

    @Override
    public Response intercept(Chain chain) throws IOException {
        Request request = chain.request();
        Response response = null;
        IOException lastException = null;

        for (int attempt = 0; attempt <= maxRetries; attempt++) {
            try {
                if (response != null) {
                    response.close();
                }
                response = chain.proceed(request);
                if (response.isSuccessful()) {
                    return response;
                }
                // Don't retry client errors (4xx)
                if (response.code() >= 400 && response.code() < 500) {
                    return response;
                }
            } catch (IOException e) {
                lastException = e;
                Log.w(TAG, "Request attempt " + (attempt + 1) + " failed: " + e.getMessage());
            }

            if (attempt < maxRetries) {
                try {
                    long backoff = (long) Math.pow(2, attempt) * 1000;
                    Thread.sleep(backoff);
                } catch (InterruptedException e) {
                    Thread.currentThread().interrupt();
                    throw new IOException("Retry interrupted", e);
                }
            }
        }

        if (response != null) {
            return response;
        }

        throw lastException != null ? lastException : new IOException("Request failed after " + maxRetries + " retries");
    }
}


