package com.example.userapp.network;

public class Result<T> {

    private final T data;
    private final String errorMessage;
    private final boolean success;
    private final int httpCode;

    private Result(T data, String errorMessage, boolean success, int httpCode) {
        this.data = data;
        this.errorMessage = errorMessage;
        this.success = success;
        this.httpCode = httpCode;
    }

    public static <T> Result<T> success(T data) {
        return new Result<>(data, null, true, 200);
    }

    public static <T> Result<T> success(T data, int httpCode) {
        return new Result<>(data, null, true, httpCode);
    }

    public static <T> Result<T> error(String message) {
        return new Result<>(null, message, false, -1);
    }

    public static <T> Result<T> error(String message, int httpCode) {
        return new Result<>(null, message, false, httpCode);
    }

    public T getData() { return data; }
    public String getErrorMessage() { return errorMessage; }
    public boolean isSuccess() { return success; }
    public int getHttpCode() { return httpCode; }
}


